#include <reg51.h>

// Define I/O pins for waveforms
sbit wave1 = P1^0;  // Waveform 1 output pin
sbit wave2 = P1^1;  // Waveform 2 output pin

// Timer reload values (high bytes only, since we avoid TL0/TL1)
#define RELOAD_T0_HIGH 0xFF  // For 0.1 ms toggle
#define RELOAD_T1_HIGH 0xFF  // For 0.2 ms toggle

// Timer interrupt service routines
void timer0_isr(void) interrupt 1 {
    TH0 = RELOAD_T0_HIGH;  // Reload high byte only
    wave1 = ~wave1;        // Toggle waveform 1
}

void timer1_isr(void) interrupt 3 {
    TH1 = RELOAD_T1_HIGH;  // Reload high byte only
    wave2 = ~wave2;        // Toggle waveform 2
}

void main(void) {
    // Initialize I/O pins
    wave1 = 0;
    wave2 = 0;

    // Configure Timer 0 for Mode 1 (16-bit timer)
    TMOD = 0x11;  // Timer 0 and Timer 1 in Mode 1

    // Set initial timer values (high bytes only, low bytes auto-loaded to 0x??)
    TH0 = RELOAD_T0_HIGH;  // High byte for Timer 0
    TH1 = RELOAD_T1_HIGH;  // High byte for Timer 1

    // Enable timer interrupts
    ET0 = 1;  // Enable Timer 0 interrupt
    ET1 = 1;  // Enable Timer 1 interrupt
    EA = 1;   // Enable global interrupts

    // Start timers
    TR0 = 1;  // Start Timer 0
    TR1 = 1;  // Start Timer 1

    // Main loop (do nothing, timers handle waveform generation)
    while (1) {
        // Idle loop
    }
}

